create table public.users (id uuid primary key references auth.users(id), created_at timestamptz default now());
create table public.reports (id uuid primary key default gen_random_uuid(), user_id uuid references public.users(id), business_type text not null, location_name text not null, geography_type text not null, state_code text, county_code text, place_code text, radius integer, target_customer text, opportunity_score integer, ai_summary text, risk_summary text, recommendation text, created_at timestamptz default now());
create table public.report_locations (id uuid primary key default gen_random_uuid(), report_id uuid references public.reports(id) on delete cascade, location_name text not null, latitude numeric, longitude numeric);
create table public.census_metrics (id uuid primary key default gen_random_uuid(), report_id uuid references public.reports(id) on delete cascade, metric_name text not null, metric_value numeric, source_year int);
create table public.ai_summaries (id uuid primary key default gen_random_uuid(), report_id uuid references public.reports(id) on delete cascade, executive_summary text, risks text, recommendation text, marketing_angle text);
